const RANGE_TO_KEYS: Record<string, string[]> = {
  "【小～特】": ["【中】", "【小】", "【大】", "【特】"],
  "【小～中】": ["【中】", "【小】"],
  "【中～特】": ["【中】", "【大】", "【特】"],
  "【大・特】": ["【大】", "【特】"],
  "【大】": ["【大】"],
};

function normalizeGeneKey(gene: string): string | null {
  if (GENE_DETAILS[gene]) return gene;
  for (const [range, keys] of Object.entries(RANGE_TO_KEYS)) {
    if (gene.endsWith(range)) {
      const base = gene.slice(0, -range.length);
      for (const k of keys) {
        const candidate = base + k;
        if (GENE_DETAILS[candidate]) return candidate;
      }
    }
  }
  return null;
}

export function getGeneDetail(gene: string): GeneDetail | null {
  const key = normalizeGeneKey(gene);
  return key ? GENE_DETAILS[key] : null;
}
